(function (Scratch) {
    'use strict';

    // 🎨 YOUR PNG SPRITE TRICK HERE:
    // Convert your exported PNG to Base64 and paste the text inside these quotes!
    const multiplayerLogo = "data:image/png;base64,";

    class Multiplayer_Mod_Extension {
        constructor() {
            this.roomName = "Lobby";
            this.playerX = 0;
            this.playerY = 0;
            this.receivedData = "No data";
        }

        getInfo() {
            return {
                id: 'multiplayermodextension',
                name: 'Multiplayer Mod',
                color1: '#4a90e2', // High-speed network blue
                color2: '#357abd',
                blockIconURI: multiplayerLogo,
                menuIconURI: multiplayerLogo,
                blocks: [
                    {
                        opcode: 'connectToRoom',
                        blockType: Scratch.BlockType.COMMAND,
                        text: 'connect to multiplayer room name ID',
                        arguments: {
                            ID: { type: Scratch.BlockType.STRING, defaultValue: 'Room1' }
                        }
                    },
                    {
                        opcode: 'sendPlayerCoordinates',
                        blockType: Scratch.BlockType.COMMAND,
                        text: 'send global position data X Y',
                        arguments: {
                            X: { type: Scratch.BlockType.NUMBER, defaultValue: 0 },
                            Y: { type: Scratch.BlockType.NUMBER, defaultValue: 0 }
                        }
                    },
                    {
                        opcode: 'getNetworkData',
                        blockType: Scratch.BlockType.REPORTER,
                        text: 'received room network data'
                    },
                    {
                        opcode: 'isOnlineConnected',
                        blockType: Scratch.BlockType.BOOLEAN,
                        text: 'is server connection active'
                    }
                ]
            };
        }

        connectToRoom(args) {
            this.roomName = String(args.ID);
        }

        sendPlayerCoordinates(args) {
            this.playerX = Number(args.X);
            this.playerY = Number(args.Y);
            this.receivedData = "X " + this.playerX + " Y " + this.playerY;
        }

        getNetworkData() {
            return this.receivedData;
        }

        isOnlineConnected() {
            return navigator.onLine;
        }
    }

    Scratch.extensions.register(new Multiplayer_Mod_Extension());
})(Scratch);
